SELECT COUNT(*)
FROM device
WHERE (deleted IS NULL OR deleted = 0)
  AND DATE (device_insql_time)
    < #{localdate}
  AND DATE (device_changesql_time) = #{localdate}

SELECT *
FROM device


        AND device_name LIKE CONCAT('%', #{params.keyword}, '%')


        AND device_introduce LIKE CONCAT('%', #{params.introduce}, '%')


        AND device_class_id = #{params.classId}


        AND device_style_id = #{params.styleId}


        AND device_type_id = #{params.typeId}


        AND device_country_id = #{params.countryId}


        AND device_news_time  >=  #{params.startDate}


        AND device_news_time  <=  #{params.endDate}

